INSERT INTO chat_macros (user_id, title, content, shortcut, category, tenant_id, is_private) VALUES
('21aa0988-c5ea-4961-9884-36d2a69b24c1', 'Bom dia!', E'Olá! Bom dia! Tudo bem?\n\nComo posso te ajudar?', '/bd', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('21aa0988-c5ea-4961-9884-36d2a69b24c1', 'Tarde!', E'Olá! Boa tarde! tudo bem com você?\n\nComo posso te ajudar?', '/tarde', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('21aa0988-c5ea-4961-9884-36d2a69b24c1', 'Finalização', E'Entendido.\n\nQualquer dúvida pode nos chamar por aqui! Fico à disposição!\n\nTenha um ótimo dia. 😊', '/bye', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('21aa0988-c5ea-4961-9884-36d2a69b24c1', 'Por nada', E'Por nada!\n\nFora essa questão, posso te ajudar em algo mais?', '/por', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('21aa0988-c5ea-4961-9884-36d2a69b24c1', 'Volta almoço', E'Já retornei do meu intervalo e podemos dar continuidade no atendimento.\n\nQualquer dúvida pode nos chamar por aqui! Fico à disposição!', '/volta', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('c148f8fe-000d-4cbf-be57-159dbdad29f5', 'bye dia', E'Imagina, foi um prazer te ajudar hoje!\n\nSempre que precisar, estou a disposição!\n\nTenha um excelente dia! 😊️', '/bd', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('c148f8fe-000d-4cbf-be57-159dbdad29f5', 'bye tarde', E'Imagina, foi um prazer te ajudar hoje!\n\nSempre que precisar, estou a disposição!\n\nTenha uma excelente semana! 😊️', '/bt', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('c148f8fe-000d-4cbf-be57-159dbdad29f5', 'por nada', 'Por nada! Além desta questão te ajudo com algo mais hoje?', '/pa', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('c148f8fe-000d-4cbf-be57-159dbdad29f5', 'oi dia', E'Olá, Bom dia! Tudo bem? 😊️\n\nComo posso te ajudar hoje?', '/oid', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('c148f8fe-000d-4cbf-be57-159dbdad29f5', 'oi tarde', E'Olá, Boa tarde! Tudo bem? 😊️\n\nComo posso te ajudar hoje?', '/oit', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('c148f8fe-000d-4cbf-be57-159dbdad29f5', 'mais detalhes', 'Poderia me dar mais detalhes sobre o que precisa hoje?', '+', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', false),
('c148f8fe-000d-4cbf-be57-159dbdad29f5', 'Atendimento', E'Sobre nosso atendimento, segue o horário: de segunda a sexta-feira, das 09h às 18h (horário de Brasília).\n\nNosso suporte é realizado exclusivamente via chat ou pelo e-mail suporte@marqponto.com.br. Devido à alta demanda, não oferecemos atendimento por telefone, mas estou à disposição para esclarecer suas dúvidas por aqui.\n\nPara agilizar e otimizar nosso atendimento, sugiro que tratemos desse assunto via chat. Assim, podemos trocar informações de maneira rápida e direta.', '/atendimento', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', false),
('c148f8fe-000d-4cbf-be57-159dbdad29f5', 'Solicitação cancelamento', E'Para solicitações de cancelamento é necessário o preenchimento do formulário do link abaixo:\n\nhttps://app.marqponto.com.br/cancelamento\n\nCom o preenchimento dos dados é aberta a solicitação de cancelamento para nossa equipe responsável, assim podemos dar sequência no desligamento da empresa.\n\nA empresa não é desativada de imediato, a solicitação é aberta e a equipe responsável realizará um contato para confirmar o pedido.\n\nUma pena que estejamos nos distanciando 😭\n\nMas qualquer questão, pode contar conosco! Aqui em nosso atendimento via Chat enquanto sua empresa ainda estiver ativa, ou no e-mail suporte@marqponto.com.br', '/solicitação-cancelamento', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', false),
('58dd7b3c-5844-4177-baf0-2ef09714aa2a', 'Algo mais', 'Fora essa questão, há mais alguma coisa em que eu possa ajudar?', 'Algo mais', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('58dd7b3c-5844-4177-baf0-2ef09714aa2a', 'Financeiro', E'Entendo, nesse caso o ideal é que entre em contato com nosso setor financeiro, para obter uma resposta mais assertiva. Você pode utilizar um dos seguintes canais para falar com a nossa equipe financeira:\n\nE-mail: contas@marqponto.com.br\n\nOu whatsapp, temos dois contatos, sendo:\n\n+55 41 9529-7768 - Para questões como: renovações, aumento de acessos, migração de planos, novas contratações de base e negociação do plano.\n\n41 9209-0504 - Para questões como: Inadimplência, boletos, nota fiscal, bloqueio e desbloqueio de bases.', '/Financeiro', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', false),
('58dd7b3c-5844-4177-baf0-2ef09714aa2a', 'Fim do dia', 'Estamos encerrando o expediente por hoje, caso tenha mais algum assunto pode deixar aqui no chat que retornamos amanhã como prioridade! Finalizamos as 18h mas às 09:00 de Brasília já estamos online.', 'Fim do dia', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', false),
('58dd7b3c-5844-4177-baf0-2ef09714aa2a', 'Almoço', 'Estou me ausentando para realizar meu intervalo e nós damos continuidade assim que retornar, tudo bem?', 'Almoço', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', false),
('58dd7b3c-5844-4177-baf0-2ef09714aa2a', 'Detalhes', 'Para que eu possa analisar melhor, você poderia me confirmar o nome do colaborador e a data em que notou essa situação ocorrer?', 'detalhes', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('58dd7b3c-5844-4177-baf0-2ef09714aa2a', 'Inativar dias', E'Feito!\n\nConforme solicitado dias inativos para ele por aqui.\n\nO mesmo tendo dias ativos agora somente de xx/xx em diante.', 'Inativar dias', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('58dd7b3c-5844-4177-baf0-2ef09714aa2a', 'Obrigado', 'Obrigado pela confirmação. Irei analisar por aqui, logo retorno', 'obrigado', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('58dd7b3c-5844-4177-baf0-2ef09714aa2a', 'Trasnferir atendimento', E'Obrigado pela confirmação!\n\nIrei transferir seu atendimento para um de nossos atendentes.\nPor favor, encaminhe sua dúvida abaixo para que eles possam analisá-la e retornar assim que possível.', 'Trasnferir atendimento', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('58dd7b3c-5844-4177-baf0-2ef09714aa2a', 'CNPJ', 'Antes de darmos sequência ao seu atendimento, poderia, por gentileza, confirmar o CNPJ da empresa?', 'cnpj', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
('58dd7b3c-5844-4177-baf0-2ef09714aa2a', 'Qualquer duvida', E'Qualquer dúvida pode nos chamar por aqui! Fico à disposição!\n\nTenha um ótimo dia. 😊', 'qualquer duvida', NULL, 'eee96b59-d7da-45cf-93f1-e3ab0796e678', true),
